import java.util.ArrayList;import java.util.LinkedHashMap;import java.util.List;import java.util.Map;
final class PrototypePattern{static final class PatternException extends RuntimeException{private final String code;PatternException(String c){super(c);code=c;}String code(){return code;}}
  static final class RoutingPolicy{String name,primary;List<String>fallbacks;RoutingPolicy(String n,String p,List<String>f){name=n;primary=p;fallbacks=new ArrayList<>(f);}RoutingPolicy copy(){return new RoutingPolicy(name+"-copy",primary,fallbacks);}Map<String,Object>value(){Map<String,Object>m=new LinkedHashMap<>();m.put("name",name);m.put("primary",primary);m.put("fallbacks",new ArrayList<>(fallbacks));return m;}}
  @SuppressWarnings("unchecked")static Object evaluate(Map<String,Object>input){Map<String,Object>b=(Map<String,Object>)input.get("base");String n=String.valueOf(b.getOrDefault("name","")),p=String.valueOf(b.getOrDefault("primary",""));if(n.isEmpty()||p.isEmpty())throw new PatternException("invalid_prototype");RoutingPolicy original=new RoutingPolicy(n,p,(List<String>)b.getOrDefault("fallbacks",List.of()));RoutingPolicy copy=original.copy();if(input.containsKey("override_primary"))copy.primary=String.valueOf(input.get("override_primary"));if(input.containsKey("append_fallback"))copy.fallbacks.add(String.valueOf(input.get("append_fallback")));Map<String,Object>r=new LinkedHashMap<>();r.put("original",original.value());r.put("clone",copy.value());return r;}}
